-- =============================================================================
-- Full 2026 budget apply from public._budget_truth_csv with agreed mapping rules.
--
-- Input:
--   public._budget_truth_csv generated by scripts/reconcile-budget-csv.mjs
--   Columns: initiative, budget_department, q1..q4, is_in_pnl_it.
--
-- Applies:
--   - direct rows for initiatives with a unique name in public.initiatives;
--   - agreed MAP / CREATE / REDISTRIBUTE / SKIP rules from the previous flow;
--   - full rewrite of initiative_budget_department_2026;
--   - 2026 quarterly_data cost = sum of final budget split;
--   - 2025-Q* keys removed from initiatives.quarterly_data.
-- Uses public._budget_2026_* staging tables instead of TEMP tables because
-- Supabase SQL Editor may commit between statements and drop ON COMMIT tables.
-- =============================================================================

DO $guard$
BEGIN
  IF to_regclass('public._budget_truth_csv') IS NULL THEN
    RAISE EXCEPTION 'Нет public._budget_truth_csv. Сначала выполните сгенерированный *-truth-insert.sql';
  END IF;

  IF to_regclass('public.initiative_budget_department_2026') IS NULL THEN
    RAISE EXCEPTION 'Нет public.initiative_budget_department_2026. Сначала примените миграцию таблицы разбивки';
  END IF;
END
$guard$;

ALTER TABLE public.initiative_budget_department_2026
  ADD COLUMN IF NOT EXISTS is_in_pnl_it boolean NOT NULL DEFAULT true;

ALTER TABLE public.initiative_budget_department_2026
  ADD COLUMN IF NOT EXISTS created_at timestamptz NOT NULL DEFAULT timezone('utc'::text, now());

ALTER TABLE public.initiative_budget_department_2026
  ADD COLUMN IF NOT EXISTS updated_at timestamptz NOT NULL DEFAULT timezone('utc'::text, now());

BEGIN;

CREATE TABLE IF NOT EXISTS public.budget_import_2026_rules (
  source_initiative text NOT NULL,
  budget_department text NOT NULL,
  action text NOT NULL CHECK (action IN ('MAP','CREATE','REDISTRIBUTE','SKIP')),
  target_initiative_id uuid,
  create_unit text,
  create_team text,
  create_initiative text,
  note text,
  created_at timestamptz NOT NULL DEFAULT now(),
  PRIMARY KEY (source_initiative, budget_department)
);

DROP TABLE IF EXISTS public.budget_import_2026_exceptions;
CREATE TABLE public.budget_import_2026_exceptions (
  reason text NOT NULL,
  initiative text,
  details jsonb,
  created_at timestamptz NOT NULL DEFAULT now()
);

DROP TABLE IF EXISTS
  public._budget_2026_final_sum,
  public._budget_2026_final_rows,
  public._budget_2026_redist_alloc,
  public._budget_2026_recipients,
  public._budget_2026_redist_source,
  public._budget_2026_unresolved,
  public._budget_2026_mapped,
  public._budget_2026_create_defs,
  public._budget_2026_ini_once,
  public._budget_2026_src;

CREATE TABLE public._budget_2026_src AS
SELECT
  trim(initiative) AS source_initiative,
  trim(budget_department) AS budget_department,
  sum(q1)::numeric AS q1,
  sum(q2)::numeric AS q2,
  sum(q3)::numeric AS q3,
  sum(q4)::numeric AS q4,
  bool_or(coalesce(is_in_pnl_it, true)) AS is_in_pnl_it
FROM public._budget_truth_csv
WHERE trim(coalesce(initiative, '')) <> ''
GROUP BY 1, 2;

CREATE TABLE public._budget_2026_ini_once AS
SELECT
  trim(initiative) AS source_initiative,
  (array_agg(id ORDER BY id))[1] AS initiative_id
FROM public.initiatives
WHERE coalesce(is_timeline_stub, false) = false
GROUP BY trim(initiative)
HAVING count(*) = 1;

-- Hand-agreed MAP rules.
INSERT INTO public.budget_import_2026_rules (source_initiative, budget_department, action, target_initiative_id, note)
SELECT 'GDPR', dep, 'MAP', (array_agg(i.id ORDER BY i.id))[1], 'GDPR -> TMNT'
FROM (VALUES
  ('IT.App & Web.Core'),
  ('IT.App & Web.Management'),
  ('IT.Management')
) d(dep)
JOIN public.initiatives i
  ON i.initiative = 'GDPR' AND i.unit = 'App&Web' AND i.team = 'TMNT'
GROUP BY dep
ON CONFLICT (source_initiative, budget_department) DO UPDATE
SET action = excluded.action, target_initiative_id = excluded.target_initiative_id, note = excluded.note;

INSERT INTO public.budget_import_2026_rules (source_initiative, budget_department, action, target_initiative_id, note)
SELECT 'GDPR Postal', dep, 'MAP', (array_agg(i.id ORDER BY i.id))[1], 'GDPR Postal -> App&Web/Postal'
FROM (VALUES
  ('IT.App & Web.Management'),
  ('IT.App & Web.Postal'),
  ('IT.Management')
) d(dep)
JOIN public.initiatives i
  ON i.initiative = 'GDPR' AND i.unit = 'App&Web' AND i.team = 'Postal'
GROUP BY dep
ON CONFLICT (source_initiative, budget_department) DO UPDATE
SET action = excluded.action, target_initiative_id = excluded.target_initiative_id, note = excluded.note;

INSERT INTO public.budget_import_2026_rules (source_initiative, budget_department, action, target_initiative_id, note)
SELECT 'Динамический промис', dep, 'MAP', (array_agg(i.id ORDER BY i.id))[1], 'Client Platform -> Peaches'
FROM (VALUES
  ('IT.Client Platform.Management'),
  ('IT.Client Platform.Personalisation')
) d(dep)
JOIN public.initiatives i
  ON i.initiative = 'Динамический промис' AND i.unit = 'Client Platform' AND i.team = 'Peaches'
GROUP BY dep
ON CONFLICT (source_initiative, budget_department) DO UPDATE
SET action = excluded.action, target_initiative_id = excluded.target_initiative_id, note = excluded.note;

INSERT INTO public.budget_import_2026_rules (source_initiative, budget_department, action, target_initiative_id, note)
SELECT 'Динамический промис', 'IT.Data Office.AI Lab', 'MAP', (array_agg(i.id ORDER BY i.id))[1], 'Data Office ветка'
FROM public.initiatives i
WHERE i.initiative = 'Динамический промис' AND i.unit = 'Data Office' AND i.team = 'Personalisation'
GROUP BY i.initiative
ON CONFLICT (source_initiative, budget_department) DO UPDATE
SET action = excluded.action, target_initiative_id = excluded.target_initiative_id, note = excluded.note;

