INSERT INTO public.budget_import_2026_rules (
  source_initiative, budget_department, action, target_initiative_id, note
)
SELECT
  s.source_initiative,
  s.budget_department,
  'MAP',
  u.initiative_id,
  'auto MAP by alias_map'
FROM public._budget_2026_src s
JOIN alias_map a ON a.source_initiative = s.source_initiative
JOIN public._budget_2026_ini_once u
  ON u.source_initiative = a.target_initiative
ON CONFLICT (source_initiative, budget_department) DO UPDATE
SET action = excluded.action,
    target_initiative_id = excluded.target_initiative_id,
    note = excluded.note;

-- Codo ФОТ ранее удалили вручную (scripts/sql/fix_codo_redistribute_to_fap.sql)
-- и её бюджет был размазан по всем FAP-инициативам с IT.FAP.Management. Чтобы повторный
-- прогон CSV-truth не падал в UNRESOLVED, делаем то же самое автоматически: REDISTRIBUTE
-- по получателям в IT.FAP.Management.
INSERT INTO public.budget_import_2026_rules (source_initiative, budget_department, action, note)
VALUES (
  'Codo ФОТ Q1 25 - Q4 26',
  'IT.FAP.Management',
  'REDISTRIBUTE',
  'Codo ФОТ ранее удалена; делим IT.FAP.Management поровну между остальными FAP-инициативами'
)
ON CONFLICT (source_initiative, budget_department) DO UPDATE
SET action = excluded.action,
    note = excluded.note;

-- 2025-only rows are redistributed inside the same budget department.
-- Чтобы total CSV сохранился (иначе 14,9M «теряются» в воздухе), эти инициативы
-- размазываются поровну между всеми получателями того же budget_department. Побочный
-- эффект — небольшой management-смазывание по живым инициативам того же департамента
-- (для App&Web ~10k/год сверху на каждую). Это лечится позже точечной чисткой ghost'ов
-- (см. scripts/out/ghost_initiatives_2026.tsv), но не ломает тотал бюджета.
INSERT INTO public.budget_import_2026_rules (source_initiative, budget_department, action, note)
SELECT DISTINCT
  s.source_initiative,
  s.budget_department,
  'REDISTRIBUTE',
  '2025-only: распределить внутри budget_department по инициативам 2026'
FROM public._budget_2026_src s
WHERE s.source_initiative IN (
  'Динамическое комбо',
  'Поиск',
  'Умный учет',
  'Computer Vision',
  'Аспелл v2',
  'Аутентификация (УБРАТЬ)',
  'Вставание в очереид по QR кода',
  'Корзина: заказжи самовывоз (скидка 10-20%)',
  'Курьер на город',
  'Мобильное приложение (MVP)',
  'Мощность пиццерии',
  'Поддержка outsource доставки в IMF',
  'Промо ресторана в приложении до 3-го заказа',
  'Улучшение отображение информации на карточках заказов КД и КП',
  'ФОТ Digital Payments Q1-Q2',
  'Peaches ФОТ команды Q1 2025',
  'Чаевые в приложении',
  'Чат "Курьер-Клиент"'
)
ON CONFLICT (source_initiative, budget_department) DO UPDATE
SET action = excluded.action,
    note = excluded.note;

-- Zero rows are ignored unless a stricter rule already exists.
INSERT INTO public.budget_import_2026_rules (source_initiative, budget_department, action, note)
SELECT
  s.source_initiative,
  s.budget_department,
  'SKIP',
  'Auto SKIP: Q1..Q4 sum = 0'
FROM public._budget_2026_src s
WHERE s.q1 + s.q2 + s.q3 + s.q4 = 0
ON CONFLICT (source_initiative, budget_department) DO NOTHING;

