INSERT INTO public.budget_import_2026_rules (
  source_initiative,
  budget_department,
  action,
  target_initiative_id,
  create_unit,
  create_team,
  create_initiative,
  note
)
SELECT
  d.source_initiative,
  s.budget_department,
  'CREATE',
  NULL,
  d.create_unit,
  d.create_team,
  d.create_initiative,
  d.note
FROM defs d
JOIN public._budget_2026_src s USING (source_initiative)
ON CONFLICT (source_initiative, budget_department) DO UPDATE
SET action = excluded.action,
    target_initiative_id = excluded.target_initiative_id,
    create_unit = excluded.create_unit,
    create_team = excluded.create_team,
    create_initiative = excluded.create_initiative,
    note = excluded.note;

CREATE TABLE public._budget_2026_create_defs AS
SELECT DISTINCT
  r.create_unit AS unit,
  r.create_team AS team,
  r.create_initiative AS initiative
FROM public.budget_import_2026_rules r
JOIN public._budget_2026_src s
  ON s.source_initiative = r.source_initiative
 AND s.budget_department = r.budget_department
WHERE r.action = 'CREATE'
  AND r.create_unit IS NOT NULL
  AND r.create_team IS NOT NULL
  AND r.create_initiative IS NOT NULL;

INSERT INTO public.initiatives (
  unit,
  team,
  initiative,
  stakeholders_list,
  description,
  documentation_link,
  stakeholders,
  quarterly_data,
  created_at,
  updated_at
)
SELECT
  d.unit,
  d.team,
  d.initiative,
  array[]::text[],
  '',
  '',
  '',
  '{}'::jsonb,
  timezone('utc'::text, now()),
  timezone('utc'::text, now())
FROM public._budget_2026_create_defs d
LEFT JOIN public.initiatives i
  ON i.unit = d.unit
 AND i.team = d.team
 AND i.initiative = d.initiative
 AND coalesce(i.is_timeline_stub, false) = false
WHERE i.id IS NULL;

UPDATE public.budget_import_2026_rules r
SET target_initiative_id = i.id
FROM public.initiatives i
WHERE r.action = 'CREATE'
  AND i.unit = r.create_unit
  AND i.team = r.create_team
  AND i.initiative = r.create_initiative
  AND coalesce(i.is_timeline_stub, false) = false;

CREATE TABLE public._budget_2026_mapped AS
SELECT
  s.source_initiative,
  s.budget_department,
  coalesce(r.target_initiative_id, u.initiative_id) AS initiative_id,
  s.q1,
  s.q2,
  s.q3,
  s.q4,
  s.is_in_pnl_it
FROM public._budget_2026_src s
LEFT JOIN public.budget_import_2026_rules r
  ON r.source_initiative = s.source_initiative
 AND r.budget_department = s.budget_department
 AND r.action IN ('MAP','CREATE')
LEFT JOIN public._budget_2026_ini_once u
  ON u.source_initiative = s.source_initiative
WHERE coalesce(r.target_initiative_id, u.initiative_id) IS NOT NULL;

CREATE TABLE public._budget_2026_unresolved AS
SELECT s.*
FROM public._budget_2026_src s
LEFT JOIN public._budget_2026_mapped m
  ON m.source_initiative = s.source_initiative
 AND m.budget_department = s.budget_department
LEFT JOIN public.budget_import_2026_rules r
  ON r.source_initiative = s.source_initiative
 AND r.budget_department = s.budget_department
WHERE m.initiative_id IS NULL
  AND coalesce(r.action, '') NOT IN ('REDISTRIBUTE','SKIP')
  AND s.q1 + s.q2 + s.q3 + s.q4 <> 0;

INSERT INTO public.budget_import_2026_exceptions(reason, initiative, details)
SELECT
  'UNRESOLVED',
  source_initiative,
  jsonb_build_object('budget_department', budget_department, 'q1', q1, 'q2', q2, 'q3', q3, 'q4', q4)
FROM public._budget_2026_unresolved;

DO $$
DECLARE
  v_unresolved int;
BEGIN
  SELECT count(*) INTO v_unresolved FROM public._budget_2026_unresolved;
  IF v_unresolved > 0 THEN
    RAISE EXCEPTION 'Есть нерешенные ненулевые пары: %. См. budget_import_2026_exceptions', v_unresolved;
  END IF;
END $$;

CREATE TABLE public._budget_2026_redist_source AS
SELECT
  s.source_initiative,
  s.budget_department,
  s.q1,
  s.q2,
  s.q3,
  s.q4,
  s.is_in_pnl_it
FROM public._budget_2026_src s
JOIN public.budget_import_2026_rules r
  ON r.source_initiative = s.source_initiative
 AND r.budget_department = s.budget_department
WHERE r.action = 'REDISTRIBUTE';

CREATE TABLE public._budget_2026_recipients AS
SELECT budget_department, initiative_id
FROM (
  SELECT budget_department, initiative_id, sum(q1 + q2 + q3 + q4) AS total_sum
  FROM public._budget_2026_mapped
  GROUP BY 1, 2
) t
WHERE total_sum > 0;

INSERT INTO public.budget_import_2026_exceptions(reason, initiative, details)
SELECT
  'REDISTRIBUTE_NO_RECIPIENT',
  rs.source_initiative,
  jsonb_build_object('budget_department', rs.budget_department)
FROM public._budget_2026_redist_source rs
LEFT JOIN public._budget_2026_recipients rc
  ON rc.budget_department = rs.budget_department
WHERE rc.initiative_id IS NULL;

DO $$
DECLARE
  v_no_recipient int;
BEGIN
  SELECT count(*) INTO v_no_recipient
  FROM public.budget_import_2026_exceptions
  WHERE reason = 'REDISTRIBUTE_NO_RECIPIENT';

  IF v_no_recipient > 0 THEN
    RAISE EXCEPTION 'Есть REDISTRIBUTE без получателя: %. См. budget_import_2026_exceptions', v_no_recipient;
  END IF;
END $$;

CREATE TABLE public._budget_2026_redist_alloc AS
WITH recipient_count AS (
  SELECT budget_department, count(*)::numeric AS cnt
  FROM public._budget_2026_recipients
  GROUP BY 1
)
SELECT
  rc.initiative_id,
  rs.budget_department,
  rs.q1 / c.cnt AS q1,
  rs.q2 / c.cnt AS q2,
  rs.q3 / c.cnt AS q3,
  rs.q4 / c.cnt AS q4,
  rs.is_in_pnl_it
FROM public._budget_2026_redist_source rs
JOIN recipient_count c
  ON c.budget_department = rs.budget_department
JOIN public._budget_2026_recipients rc
  ON rc.budget_department = rs.budget_department;

CREATE TABLE public._budget_2026_final_rows AS
SELECT
  initiative_id,
  budget_department,
  sum(q1) AS q1,
  sum(q2) AS q2,
  sum(q3) AS q3,
  sum(q4) AS q4,
  bool_or(is_in_pnl_it) AS is_in_pnl_it
FROM (
  SELECT initiative_id, budget_department, q1, q2, q3, q4, is_in_pnl_it FROM public._budget_2026_mapped
  UNION ALL
  SELECT initiative_id, budget_department, q1, q2, q3, q4, is_in_pnl_it FROM public._budget_2026_redist_alloc
) x
GROUP BY 1, 2;

CREATE TABLE public._budget_2026_final_sum AS
SELECT
  initiative_id,
  sum(q1) AS q1,
  sum(q2) AS q2,
  sum(q3) AS q3,
  sum(q4) AS q4
FROM public._budget_2026_final_rows
GROUP BY 1;

-- Full cleanup: the dashboard split table and quarterly_data must exactly reflect this CSV+rules run.
-- Zero every initiative first, including timeline stubs; otherwise the dashboard can add old
-- quarterly_data from rows that no longer have budget split allocations.
TRUNCATE public.initiative_budget_department_2026;

UPDATE public.initiatives
SET
  quarterly_data =
    jsonb_set(
      jsonb_set(
        jsonb_set(
          jsonb_set(
            jsonb_set(
              jsonb_set(
                jsonb_set(
                  jsonb_set(
                    coalesce(quarterly_data, '{}'::jsonb) - '2025-Q1' - '2025-Q2' - '2025-Q3' - '2025-Q4',
                    '{2026-Q1,cost}', to_jsonb(0::numeric), true
                  ),
                  '{2026-Q1,otherCosts}', '0'::jsonb, true
                ),
                '{2026-Q2,cost}', to_jsonb(0::numeric), true
              ),
              '{2026-Q2,otherCosts}', '0'::jsonb, true
            ),
            '{2026-Q3,cost}', to_jsonb(0::numeric), true
          ),
          '{2026-Q3,otherCosts}', '0'::jsonb, true
        ),
        '{2026-Q4,cost}', to_jsonb(0::numeric), true
      ),
      '{2026-Q4,otherCosts}', '0'::jsonb, true
    ),
  updated_at = timezone('utc'::text, now());

UPDATE public.initiatives i
SET
  quarterly_data =
    jsonb_set(
      jsonb_set(
        jsonb_set(
          jsonb_set(
            jsonb_set(
              jsonb_set(
                jsonb_set(
                  jsonb_set(
                    jsonb_set(
                      jsonb_set(
                        jsonb_set(
                          jsonb_set(
                            coalesce(i.quarterly_data, '{}'::jsonb),
                            '{2026-Q1,cost}', to_jsonb(f.q1), true
                          ),
                          '{2026-Q1,otherCosts}', '0'::jsonb, true
                        ),
                        '{2026-Q1,costFinanceConfirmed}', 'true'::jsonb, true
                      ),
                      '{2026-Q2,cost}', to_jsonb(f.q2), true
                    ),
                    '{2026-Q2,otherCosts}', '0'::jsonb, true
                  ),
                  '{2026-Q2,costFinanceConfirmed}', 'true'::jsonb, true
                ),
                '{2026-Q3,cost}', to_jsonb(f.q3), true
              ),
              '{2026-Q3,otherCosts}', '0'::jsonb, true
            ),
            '{2026-Q3,costFinanceConfirmed}', 'true'::jsonb, true
          ),
          '{2026-Q4,cost}', to_jsonb(f.q4), true
        ),
        '{2026-Q4,otherCosts}', '0'::jsonb, true
      ),
      '{2026-Q4,costFinanceConfirmed}', 'true'::jsonb, true
    ),
  updated_at = timezone('utc'::text, now())
FROM public._budget_2026_final_sum f
WHERE i.id = f.initiative_id;

INSERT INTO public.initiative_budget_department_2026 (
  initiative_id,
  budget_department,
  q1,
  q2,
  q3,
  q4,
  is_in_pnl_it,
  created_at,
  updated_at
)
SELECT
  initiative_id,
  budget_department,
  q1,
  q2,
  q3,
  q4,
  is_in_pnl_it,
  timezone('utc'::text, now()),
  timezone('utc'::text, now())
FROM public._budget_2026_final_rows
ON CONFLICT (initiative_id, budget_department) DO UPDATE SET
  q1 = excluded.q1,
  q2 = excluded.q2,
  q3 = excluded.q3,
  q4 = excluded.q4,
  is_in_pnl_it = excluded.is_in_pnl_it,
  updated_at = excluded.updated_at;

COMMIT;

SELECT
  (SELECT count(*) FROM public._budget_truth_csv) AS truth_rows,
  (SELECT count(*) FROM public.initiative_budget_department_2026) AS split_rows,
  (SELECT count(*) FROM public.budget_import_2026_exceptions) AS exception_rows,
  (SELECT round(sum(q1 + q2 + q3 + q4))::bigint FROM public._budget_truth_csv) AS truth_total,
  (SELECT round(sum(q1 + q2 + q3 + q4))::bigint FROM public.initiative_budget_department_2026) AS split_total,
  (SELECT round(sum(q1 + q2 + q3 + q4))::bigint FROM public._budget_truth_csv WHERE is_in_pnl_it) AS truth_pnl_it_total,
  (SELECT round(sum(q1 + q2 + q3 + q4))::bigint FROM public.initiative_budget_department_2026 WHERE is_in_pnl_it) AS split_pnl_it_total;

SELECT reason, initiative, details
FROM public.budget_import_2026_exceptions
ORDER BY reason, initiative
LIMIT 200;
